397	func pasteText(_ text: String, target: TargetApp) throws {
398	    switch target {
399	    case .simulator(let udid):
400	        try setSimulatorPasteboard(text, udid: udid)
401	        // Cmd+V: Command keycode=55, V keycode=9
402	        sendKeyCombo(modifiers: [55], key: 9)
403	        Thread.sleep(forTimeInterval: 0.2)
404	    case .macApp:
405	        let pasteboard = NSPasteboard.general
406	        let original = pasteboard.string(forType: .string)
407	
408	        pasteboard.clearContents()
409	        pasteboard.setString(text, forType: .string)
410	
411	        // Cmd+V: Command keycode=55, V keycode=9
412	        sendKeyCombo(modifiers: [55], key: 9)
413	        Thread.sleep(forTimeInterval: 0.15)
414	
415	        // Restore original clipboard content
416	        pasteboard.clearContents()
417	        if let original = original {
418	            pasteboard.setString(original, forType: .string)
419	        }
420	    }
421	}
