465	func handleScroll(_ parsed: ParsedOptions) throws -> Int32 {
466	    let target = try resolveTarget(from: parsed)
467	    try ensureAccessibilityTrusted()
468	    try activateTarget(target)
469	    let deltaX = try optionalDoubleOption("--delta-x", from: parsed) ?? 0
470	    let deltaY = try optionalDoubleOption("--delta-y", from: parsed) ?? 0
471	    if deltaX == 0 && deltaY == 0 {
472	        throw NativeError.invalidArguments("scroll requires --delta-x and/or --delta-y.")
473	    }
474	
475	    let xRaw = parsed.options["-x"]
476	    let yRaw = parsed.options["-y"]
477	    let xValue = xRaw.flatMap(Double.init)
478	    let yValue = yRaw.flatMap(Double.init)
479	
480	    switch target {
481	    case .simulator:
482	        let scrollPoint = try simulatorScrollAnchorPoint(x: xValue, y: yValue)
483	        let scrollDistance = simulatorScrollDistance(deltaX: deltaX, deltaY: deltaY)
484	        let start = CGPoint(x: scrollPoint.x - scrollDistance.width / 2, y: scrollPoint.y - scrollDistance.height / 2)
485	        let end = CGPoint(x: scrollPoint.x + scrollDistance.width / 2, y: scrollPoint.y + scrollDistance.height / 2)
486	
487	        let backend = resolveInputBackend(for: target)
488	        switch backend {
489	        case .indigoHID(let client):
490	            _ = client.swipe(fromX: Double(start.x), fromY: Double(start.y), toX: Double(end.x), toY: Double(end.y), duration: 0.45, steps: 18)
491	        case .cgevent:
492	            let targetUdid = simulatorUdid(from: target)
493	            let startPoint = try pointInSimulatorContent(x: Double(start.x), y: Double(start.y), udid: targetUdid)
494	            let endPoint = try pointInSimulatorContent(x: Double(end.x), y: Double(end.y), udid: targetUdid)
495	            sendSwipe(from: startPoint, to: endPoint, duration: 0.45)
496	        }
497	    case .macApp:
498	        var scrollPoint: CGPoint? = nil
499	        if let xValue, let yValue {
500	            scrollPoint = try pointForInput(x: xValue, y: yValue, for: target)
501	        }
502	        sendScrollWheel(at: scrollPoint, deltaX: Int32(deltaX), deltaY: Int32(deltaY))
503	    }
504	    return 0
505	}
