6	    let target = try resolveTarget(from: parsed)
7	    try ensureAccessibilityTrusted()
8	    try activateTarget(target)
9	    let accessibilityId = parsed.options["--id"]
10	    let accessibilityLabel = parsed.options["--label"]
11	    let includeAll = parsed.flags.contains("--all")
12	    let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
13	    let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
14	    if preDelay > 0 {
15	        Thread.sleep(forTimeInterval: preDelay)
16	    }
17	    if accessibilityId != nil || accessibilityLabel != nil {
18	        let root = try accessibilityRootElement(for: target)
19	        let searchRoot: UIElement
20	        if case .simulator = target, !includeAll {
21	            searchRoot = simulatorContentRootElement(from: root, udid: simulatorUdid(from: target)) ?? root
22	        } else {
23	            searchRoot = root
24	        }
25	
26	        guard let matchedElement = findAccessibilityElement(
27	            in: searchRoot,
28	            identifier: accessibilityId,
29	            label: accessibilityLabel
30	        ) else {
31	            var selectors: [String] = []
32	            if let accessibilityId { selectors.append("id='\(accessibilityId)'") }
33	            if let accessibilityLabel { selectors.append("label='\(accessibilityLabel)'") }
34	            let selectorText = selectors.joined(separator: " and ")
35	            if case .simulator = target, !includeAll {
36	                throw NativeError.commandFailed("No accessibility element matched \(selectorText) in simulator app content. Try --all to include Simulator chrome UI.")
37	            }
38	            throw NativeError.commandFailed("No accessibility element matched \(selectorText).")
