414	      return await runBackend(resolveTapBackend(params as TapParams), buildTapArgs(target, params as TapParams));
415	    }
416	  );
417	
418	  server.tool(
419	    "type_text",
420	    "Type text into the target app. auto resolves to paste on simulators and keyboard on macOS; simulator paste uses the simulator pasteboard, macOS paste temporarily uses the host clipboard; keyboard types character-by-character.",
421	    { ...unifiedTargetSchema, ...typeSchema },
422	    async (params) => {
423	      const validationError = validateTypeParams(params as TypeParams);
424	      if (validationError) return validationError;
425	
426	      const target = resolveUnifiedTargetArgs(params as UnifiedTargetParams);
427	      if (!Array.isArray(target)) return target;
428	
429	      const built = buildTypeArgs(target, params as TypeParams);
430	      const policy = resolveTypeTextPolicy(params as TypeParams, params as UnifiedTargetParams);
431	      const extraLines = [
432	        `Input source: ${policy.inputSource}`,
433	        `Target kind: ${policy.targetKind}`,
434	        `Requested method: ${policy.requestedMethod}`,
435	        `Used method: ${policy.usedMethod}`,
436	      ];
437	      if (policy.usedMethod === "paste") {
438	        if (policy.pasteTransport === "simulator_pasteboard") {
439	          extraLines.push("Paste transport: simulator pasteboard.");
440	          extraLines.push("Clipboard side effect: host clipboard is unchanged; the simulator pasteboard is updated for paste.");
441	        } else {
442	          extraLines.push("Paste transport: host clipboard.");
443	          extraLines.push("Clipboard side effect: host clipboard is temporarily replaced with the input text and restored after paste.");
444	        }
445	      } else {
